#include <iostream>
#include <vector>
using namespace std;
void drawPattern(int size) {
    vector<vector<int>> grid(size, vector<int>(size, 0));
    int val = 1;
    int x = size/2, y = size/2;
    int dx = 1, dy = 0;
    for (int step = 0; step < size*size; ++step) {
        grid[y][x] = val++;
        int nx = x + dx, ny = y + dy;
        if (nx >= size || nx < 0 || ny >= size || ny < 0 || grid[ny][nx]) {
            int temp = dx; dx = -dy; dy = temp;
            nx = x + dx; ny = y + dy;
        }
        x = nx; y = ny;
    }
    for (auto &row : grid) {
        for (auto &num : row) cout << num << " ";
        cout << endl;
    }
}
int main() { drawPattern(10); return 0; }
